mapper.select:
SELECT eq_id, ROUND(AVG(pm10), 2) AS pm10_avg, ROUND(MAX(pm10), 2) AS pm10_max, ROUND(MIN(pm10), 2) AS pm10_min, ROUND(AVG(pm25), 2) AS pm25_avg, ROUND(MAX(pm25), 2) AS pm25_max, ROUND(AVG(ntc_temp), 2) AS ntc_temp_avg, ROUND(MAX(ntc_temp), 2) AS ntc_temp_max, ROUND(AVG(ct1), 2) AS ct1_avg, ROUND(MAX(ct1), 2) AS ct1_max, ROUND(AVG(ct2), 2) AS ct2_avg, ROUND(MAX(ct2), 2) AS ct2_max, ROUND(AVG(ct3), 2) AS ct3_avg, ROUND(MAX(ct3), 2) AS ct3_max, ROUND(AVG(ct4), 2) AS ct4_avg, ROUND(MAX(ct4), 2) AS ct4_max, ROUND(AVG(ir_temp_max), 2) AS ir_temp_max_avg, ROUND(MAX(ir_temp_max), 2) AS ir_temp_max_max FROM sensor_reading
eq_id = #{eqId}
GROUP BY eq_id ORDER BY eq_id

SELECT sr.eq_id, e.eq_name, ROUND( 100 - ( (SUM(CASE WHEN sr.pm10 >= #{pm10Caution} THEN 1 ELSE 0 END) * 1.0 / COUNT(*)) * 0.3 + (SUM(CASE WHEN sr.ntc_temp >= #{ntcCaution} THEN 1 ELSE 0 END) * 1.0 / COUNT(*)) * 0.3 + (SUM(CASE WHEN sr.ct1 >= #{ctCaution} OR sr.ct2 >= #{ctCaution} OR sr.ct3 >= #{ctCaution} OR sr.ct4 >= #{ctCaution} THEN 1 ELSE 0 END) * 1.0 / COUNT(*)) * 0.2 + (SUM(CASE WHEN sr.ir_temp_max >= #{irCaution} THEN 1 ELSE 0 END) * 1.0 / COUNT(*)) * 0.2 ) * 100 , 1) AS score, ROUND(SUM(CASE WHEN sr.pm10 >= #{pm10Caution} THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) AS pm10_deviation, ROUND(SUM(CASE WHEN sr.ntc_temp >= #{ntcCaution} THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) AS ntc_deviation, ROUND(SUM(CASE WHEN sr.ct1 >= #{ctCaution} OR sr.ct2 >= #{ctCaution} OR sr.ct3 >= #{ctCaution} OR sr.ct4 >= #{ctCaution} THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) AS ct_deviation, ROUND(SUM(CASE WHEN sr.ir_temp_max >= #{irCaution} THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 1) AS ir_deviation FROM sensor_reading sr JOIN equipment e ON sr.eq_id = e.eq_id
sr.eq_id = #{eqId}
GROUP BY sr.eq_id, e.eq_name ORDER BY score ASC
